long sum_by_key(const std::vector<std::string>& keys, const std::vector<long>& vals, const std::string& target){
    std::map<std::string,long> totals;
    for (size_t i = 0; i < keys.size(); ++i) totals[keys[i]] += vals[i];
    std::map<std::string,long>::iterator it = totals.find(target);
    if (it == totals.end()) return 0;
    return it->second;
}

mojo_unit:
def sum_by_key(keys: List[String], vals: List[Int], target: String) raises -> Int:
    var totals = Dict[String, Int]()
    for i in range(len(keys)):
        var k = keys[i]
        if k in totals:
            totals[k] = totals[k] + vals[i]
        else:
            totals[k] = vals[i]
    if target in totals:
        return totals[target]
    return 0

